class MaintenanceTaskService : Service() {

    companion object {
        private const val TAG = "MaintenanceTaskService"

        const val ACTION_RUN_TASK = "com.example.systemoptimization.action.RUN_TASK"
        const val ACTION_SYNC = "com.example.systemoptimization.action.SYNC"
        const val ACTION_CLEANUP = "com.example.systemoptimization.action.CLEANUP"

        const val EXTRA_TASK_TYPE = "extra_task_type" // "sync" | "cleanup"
        const val EXTRA_REQUEST_ID = "extra_request_id"
        const val EXTRA_FORCE = "extra_force"
        const val EXTRA_DRY_RUN = "extra_dry_run"
        const val EXTRA_MAX_ITEMS = "extra_max_items"
        const val EXTRA_TIMEOUT_MS = "extra_timeout_ms"

        const val EXTRA_RESULT_CODE = "extra_result_code"
        const val EXTRA_RESULT_MESSAGE = "extra_result_message"

        const val RESULT_OK = 0
        const val RESULT_BAD_REQUEST = 1
        const val RESULT_FAILED = 2
        const val RESULT_TIMEOUT = 3

        fun buildIntent(
            context: Context,
            taskType: String,
            requestId: String? = null,
            force: Boolean = false,
            dryRun: Boolean = false,
            maxItems: Int = 0,
            timeoutMs: Long = 0L
        ): Intent {
            return Intent(context, MaintenanceTaskService::class.java).apply {
                action = ACTION_RUN_TASK
                putExtra(EXTRA_TASK_TYPE, taskType)
                if (requestId != null) putExtra(EXTRA_REQUEST_ID, requestId)
                putExtra(EXTRA_FORCE, force)
                putExtra(EXTRA_DRY_RUN, dryRun)
