        }

        val requestId = intent.getStringExtra(EXTRA_REQUEST_ID) ?: "req-$startId"
        val force = intent.getBooleanExtra(EXTRA_FORCE, false)
        val dryRun = intent.getBooleanExtra(EXTRA_DRY_RUN, false)
        val maxItems = intent.getIntExtra(EXTRA_MAX_ITEMS, 0).coerceAtLeast(0)
        val timeoutMs = intent.getLongExtra(EXTRA_TIMEOUT_MS, 0L).coerceAtLeast(0L)

        runningCount.incrementAndGet()

