    private fun runTask(
        taskType: String,
        requestId: String,
        force: Boolean,
        dryRun: Boolean,
        maxItems: Int,
        timeoutMs: Long
    ): TaskResult {
        val startedAt = System.nanoTime()

        fun timedOut(): Boolean {
            if (timeoutMs <= 0) return false
            val elapsedMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startedAt)
            return elapsedMs > timeoutMs
        }

        return try {
            when (taskType) {
                "sync" -> {
                    val synced = performDataSync(
                        requestId = requestId,
                        force = force,
                        dryRun = dryRun,
                        maxItems = maxItems,
                        timedOut = ::timedOut
                    )
                    if (timedOut()) TaskResult(RESULT_TIMEOUT, "Sync timed out", requestId, taskType, synced)
                    else TaskResult(RESULT_OK, "Sync completed", requestId, taskType, synced)
                }
                "cleanup" -> {
                    val cleaned = performCleanup(
                        requestId = requestId,
                        force = force,
                        dryRun = dryRun,
                        maxItems = maxItems,
                        timedOut = ::timedOut
