                    if (timedOut()) TaskResult(RESULT_TIMEOUT, "Cleanup timed out", requestId, taskType, cleaned)
                    else TaskResult(RESULT_OK, "Cleanup completed", requestId, taskType, cleaned)
                }
                else -> TaskResult(RESULT_BAD_REQUEST, "Unknown task type", requestId, taskType, 0)
