package com.example.systemoptimization

import android.content.BroadcastReceiver
import android.content.Context
import android.content.Intent
import android.os.Build

class MaintenanceTaskReceiver : BroadcastReceiver() {
    override fun onReceive(context: Context, intent: Intent) {
        val serviceIntent = Intent(context, MaintenanceTaskService::class.java).apply {
            action = intent.action ?: MaintenanceTaskService.ACTION_RUN_TASK
            replaceExtras(intent.extras ?: return)
        }
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            context.startForegroundService(serviceIntent)
        } else {
            context.startService(serviceIntent)
        }
    }
}

package com.example.systemoptimization

import android.app.Notification
import android.app.NotificationChannel
import android.app.NotificationManager
import android.app.Service
import android.content.Context
import android.os.Build

object ForegroundHelper {
    private const val CHANNEL_ID = "maintenance_tasks"
    private const val CHANNEL_NAME = "Maintenance Tasks"

    fun ensureChannel(context: Context) {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val nm = context.getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
            val existing = nm.getNotificationChannel(CHANNEL_ID)
            if (existing == null) {
                nm.createNotificationChannel(
                    NotificationChannel(CHANNEL_ID, CHANNEL_NAME, NotificationManager.IMPORTANCE_LOW).apply {
                        description = "Background maintenance tasks"
                        setShowBadge(false)
                    }
                )
            }
        }
    }

    fun buildNotification(context: Context, text: String): Notification {
        ensureChannel(context)
        val builder = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            Notification.Builder(context, CHANNEL_ID)
        } else {
            @Suppress("DEPRECATION")
            Notification.Builder(context)
        }
        return builder
            .setContentTitle("System Optimization")
            .setContentText(text)
            .setSmallIcon(android.R.drawable.stat_notify_sync)
            .setOngoing(true)
            .build()
    }

    fun startForegroundIfRequired(service: Service, notificationId: Int, text: String) {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            service.startForeground(notificationId, buildNotification(service, text))
        }
    }
}